from kafka import KafkaConsumer
import json

# Define a base handler class
class MessageHandler:
    def handle(self, message):
        raise NotImplementedError("Subclasses must implement this method")

# Example of a specific message handler
class TransactionHandler(MessageHandler):
    def handle(self, transaction):
        # Implement business logic for processing the transaction
        print(f"Processing transaction: {transaction}")

def deserialize_message(message_value):
    try:
        return json.loads(message_value)
    except json.JSONDecodeError as e:
        print(f"Failed to decode message: {e}")
        return None

def main():
    # Kafka consumer configuration
    consumer = KafkaConsumer(
        'financial_transactions',
        bootstrap_servers=['localhost:9092'],
        auto_offset_reset='earliest',
        enable_auto_commit=True,
        group_id='transaction-group'
    )

    # Message handlers registry
    message_handlers = {
        "transaction": TransactionHandler()
    }

    for message in consumer:
        message_value = deserialize_message(message.value)
        if not message_value:
            continue

        # Determine the type of message and handle it accordingly
        message_type = message_value.get('type')
        handler = message_handlers.get(message_type)

        if handler:
            handler.handle(message_value)
        else:
            print(f"No handler found for message type: {message_type}")

if __name__ == '__main__':
    main()